针对微信文章标题结构解析，这里提供专业级解决方案，能够智能识别三级标题结构并保留原始格式：

```python
import requests
from bs4 import BeautifulSoup, Tag
import re

def structured_parser(url):
    """ 微信文章结构化解析器 """
    headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36...',
        'Referer': 'https://mp.weixin.qq.com/'
    }

    try:
        response = requests.get(url, headers=headers, timeout=10)
        soup = BeautifulSoup(response.text, 'lxml')

        # 主标题提取（适配新旧版本）
        main_title = soup.find(['h1', 'h2'], {'id': re.compile(r'activity-name|title')}) or \
                    soup.find('title')
        main_title = main_title.get_text().strip() if main_title else '无标题'

        # 正文结构化处理
        content = []
        js_content = soup.find('div', id='js_content')
        if js_content:
            current_section = {'type': 'section', 'level': 0, 'content': []}

            for element in js_content.children:
                if not isinstance(element, Tag):
                    continue

                # 识别标题层级
                if element.name in ['h1', 'h2', 'h3']:
                    level = int(element.name[1])
                    content.append({
                        'type': 'heading',
                        'level': level,
                        'text': element.get_text().strip(),
                        'font_size': element.attrs.get('style', '')
                    })
                elif element.name == 'section':
                    # 处理微信特有section结构
                    self._process_section(element, content)
                elif element.name == 'p':
                    # 处理带样式的段落标题
                    self._process_paragraph(element, content)
                else:
                    # 普通段落处理
                    text = self._clean_text(element.get_text())
                    if text:
                        content.append({'type': 'paragraph', 'text': text})

        return {
            'main_title': main_title,
            'structure': content,
            'source': url
        }

    except Exception as e:
        return {'error': str(e)}

def _process_section(self, element, content):
    """ 处理微信section结构 """
    header = element.find(['h1', 'h2', 'h3', 'strong'])
    if header:
        level = 2 if header.name in ['h3', 'strong'] else 1
        content.append({
            'type': 'heading',
            'level': level,
            'text': header.get_text().strip(),
            'section': True
        })

    # 提取section内文本
    for p in element.find_all('p', recursive=False):
        text = self._clean_text(p.get_text())
        if text:
            content.append({'type': 'paragraph', 'text': text})

def _process_paragraph(self, element, content):
    """ 识别段落中的标题 """
    text = self._clean_text(element.get_text())
    style = element.attrs.get('style', '')

    # 通过样式识别标题
    if 'font-size:' in style:
        size_match = re.search(r'font-size:(\d+)px', style)
        if size_match:
            size = int(size_match.group(1))
            level = 1 if size >= 18 else 2 if size >= 16 else 3
            content.append({
                'type': 'heading', 
                'level': level,
                'text': text,
                'style': style
            })
            return

    # 通过特殊符号识别
    if re.match(r'^(【.+】|第[一二三四五六七八九十]+章)', text):
        content.append({
            'type': 'heading',
            'level': 2,
            'text': text
        })
    else:
        content.append({'type': 'paragraph', 'text': text})

def _clean_text(self, text):
    """ 清理空白字符 """
    text = re.sub(r'\s+', ' ', text).strip()
    return text if text and not re.match(r'^[\s\u3000]*$', text) else None

# 使用示例
if __name__ == "__main__":
    result = structured_parser("https://mp.weixin.qq.com/s/xxxxxx")

    # 可视化输出
    print(f"主标题：{result['main_title']}\n")
    print("文章结构：")
    for item in result['structure']:
        if item['type'] == 'heading':
            prefix = '#' * item['level']
            print(f"\n{prefix} {item['text']}")
        else:
            print(f"│ {item['text'][:50]}...")

    # 导出Markdown
    with open('output.md', 'w', encoding='utf-8') as f:
        f.write(f"# {result['main_title']}\n\n")
        for item in result['structure']:
            if item['type'] == 'heading':
                f.write(f"\n{'#' * (item['level'] + 1)} {item['text']}\n")
            else:
                f.write(f"{item['text']}\n\n")
```

**核心功能解析：**

1. **四级标题识别体系**：
   - `level 0`：文章主标题（自动提取）
   - `level 1`：章节大标题（h1/h2标签或大字号）
   - `level 2`：子标题（h3标签/中等字号/特殊符号）
   - `level 3`：小节标题（小字号/特殊格式）

2. **智能识别策略**：
   ```python
   # 识别方式优先级：
   1. HTML标签（h1 > h2 > h3）
   2. 字体大小（style中的font-size）
   3. 特殊符号（【】、第X章等）
   4. 结构特征（section嵌套）
   ```

