```python
import os
import json
from datetime import datetime
import markdown
from bs4 import BeautifulSoup
from weasyprint import HTML

class ArticleExporter:
    def __init__(self, article_data, image_dir='images'):
        """
        :param article_data: 包含标题、内容、元数据的字典
        :param image_dir: 图片存储目录
        """
        self.article = article_data
        self.image_dir = image_dir
        self.output_dir = 'output'
        os.makedirs(self.output_dir, exist_ok=True)

    def _sanitize_filename(self, name):
        """ 生成安全的文件名 """
        name = re.sub(r'[\\/*?:"<>|]', "", name)[:50]
        return name.strip()

    def export(self, formats=['html', 'md', 'pdf']):
        """ 批量导出文件 """
        base_name = self._sanitize_filename(self.article['title'])
        results = {}

        if 'md' in formats:
            md_path = os.path.join(self.output_dir, f"{base_name}.md")
            self._save_markdown(md_path)
            results['markdown'] = md_path

        if 'html' in formats:
            html_path = os.path.join(self.output_dir, f"{base_name}.html")
            self._save_html(html_path)
            results['html'] = html_path

        if 'pdf' in formats:
            pdf_path = os.path.join(self.output_dir, f"{base_name}.pdf")
            self._save_pdf(html_path, pdf_path)  # 需要先生成HTML
            results['pdf'] = pdf_path

        return results

    def _save_markdown(self, path):
        """ 导出为Markdown格式 """
        content = [
            f"# {self.article['title']}\n",
            f"**作者**: {self.article['meta']['author']}  ",
            f"**发布时间**: {self.article['meta']['publish_time']}\n\n"
        ]

        # 解析内容结构
        for elem in self.article['structure']:
            if elem['type'] == 'heading':
                content.append(f"\n{'#' * (elem['level']+1)} {elem['text']}\n")
            elif elem['type'] == 'paragraph':
                content.append(f"{elem['text']}\n\n")
            elif elem['type'] == 'image_caption':
                content.append(f"![{elem['text']}]({self._local_image_path(elem['src'])})\n")

        with open(path, 'w', encoding='utf-8') as f:
            f.write(''.join(content))

    def _save_html(self, path):
        """ 导出为响应式HTML """
        soup = BeautifulSoup("""
            <!DOCTYPE html>
            <html>
            <head>
                <meta charset="utf-8">
                <title>{title}</title>
                <style>
                    {css}
                </style>
            </head>
            <body>
                <article class="weixin-article"></article>
            </body>
            </html>
        """, 'html.parser')

        # 添加CSS样式
        with open('style.css', 'r', encoding='utf-8') as f:
            css = f.read()
        soup.style.string = css

        # 构建文章内容
        article = soup.find('article')
        title = soup.new_tag('h1', class_='article-title')
        title.string = self.article['title']
        article.append(title)

        meta = soup.new_tag('div', class_='article-meta')
        meta.append(f"作者：{self.article['meta']['author']} | ")
        meta.append(f"发布时间：{self.article['meta']['publish_time']} | ")
        meta.append(f"阅读量：{self.article['meta']['read_count']}")
        article.append(meta)

        # 添加正文内容
        content = soup.new_tag('div', class_='article-content')
        for elem in self.article['structure']:
            if elem['type'] == 'heading':
                tag = soup.new_tag(f'h{elem["level"]+1}')
                tag.string = elem['text']
                content.append(tag)
            elif elem['type'] == 'paragraph':
                p = soup.new_tag('p')
                p.string = elem['text']
                content.append(p)
            elif elem['type'] == 'image_caption':
                figure = soup.new_tag('figure')
                img = soup.new_tag('img', src=self._local_image_path(elem['src']))
                figcaption = soup.new_tag('figcaption')
                figcaption.string = elem['text']
                figure.append(img)
                figure.append(figcaption)
                content.append(figure)

        article.append(content)

        # 保存文件
        with open(path, 'w', encoding='utf-8') as f:
            f.write(str(soup.prettify()))

    def _save_pdf(self, html_path, pdf_path):
        """ 基于HTML生成PDF """
        HTML(html_path).write_pdf(pdf_path)

    def _local_image_path(self, original_url):
        """ 匹配本地图片路径 """
        # 查找已下载的图片
        for img in self.article.get('images', []):
            if img['url'] == original_url and img['status'] == 'success':
                return os.path.relpath(img['path'], self.output_dir)
        return original_url  # 未找到则保留原始链接

# CSS样式表示例（保存为style.css）
"""
.weixin-article {
    max-width: 680px;
    margin: 0 auto;
    padding: 20px;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif;
    line-height: 1.6;
}

.article-title {
    color: #2d2d2d;
    border-bottom: 1px solid #eee;
    padding-bottom: 0.5em;
}

.article-meta {
    color: #666;
    font-size: 0.9em;
    margin: 1em 0;
}

figure {
    margin: 20px 0;
    text-align: center;
}

figcaption {
    color: #666;
    font-size: 0.9em;
    margin-top: 8px;
}

img {
    max-width: 100%;
    height: auto;
    border-radius: 4px;
}

h2 { color: #1a1a1a; }
h3 { color: #2d2d2d; }
"""

# 使用示例
if __name__ == "__main__":
    # 假设已有抓取数据（需包含图片下载信息）
    sample_data = {
        'title': '人工智能发展白皮书',
        'meta': {
            'author': '科技前沿',
            'publish_time': '2024-03-15',
            'read_count': '10w+'
        },
        'structure': [
            {'type': 'heading', 'level': 1, 'text': '核心技术'},
            {'type': 'paragraph', 'text': '深度学习是当前主流...'},
            {'type': 'image_caption', 'text': '技术架构图', 'src': 'https://...'},
            {'type': 'heading', 'level': 2, 'text': '应用场景'},
            {'type': 'paragraph', 'text': '在医疗领域...'}
        ],
        'images': [
            {'url': 'https://...', 'path': 'images/001_a3f58b.jpg', 'status': 'success'}
        ]
    }

    exporter = ArticleExporter(sample_data, image_dir='images')
    result_files = exporter.export(formats=['html', 'md', 'pdf'])

    print("导出完成！生成文件：")
    for fmt, path in result_files.items():
        print(f"- {fmt.upper()}: {path}")
```

